import { Request, Response, NextFunction } from 'express';

const requestCounts = new Map<string, { count: number; resetTime: number }>();

const WINDOW_MS = 60000;
const MAX_REQUESTS = 100;

export function rateLimit(req: Request, res: Response, next: NextFunction) {
  const ip = req.ip || 'unknown';
  const now = Date.now();
  const record = requestCounts.get(ip);

  if (!record || now > record.resetTime) {
    requestCounts.set(ip, { count: 1, resetTime: now + WINDOW_MS });
    return next();
  }

  record.count++;

  if (record.count > MAX_REQUESTS) {
    return res.status(429).json({ error: 'Too many requests' });
  }

  next();
}

import express from 'express';
import { apiRouter } from './routes/api';
import { rateLimit } from './middleware/rateLimit';
import cors from 'cors';

const app = express();

app.use(cors());
app.use(express.json());
app.use('/api', apiRouter);
app.use(rateLimit);

export { app };

Found the real problem. The rate limiter is registered AFTER the routes. In Express, middleware runs in the order it's added — so `app.use('/api', apiRouter)` handles and responds to requests before the rate limiter ever runs. My initial instinct was to look for a bug in the rate limit logic, but the logic is fine. The issue is middleware ordering.

